import{_ as a,a as e,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as o,o as i,c as n,a2 as h}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"冗長バックアップと読み取り元切り替え","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/redundant-backup-and-read-source.md","filePath":"ja-JP/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"ja-JP/Other/redundant-backup-and-read-source.md"};function s(p,t,c,b,u,_){return i(),n("div",null,[...t[0]||(t[0]=[h('<h1 id="冗長バックアップと読み取り元切り替え" tabindex="-1">冗長バックアップと読み取り元切り替え <a class="header-anchor" href="#冗長バックアップと読み取り元切り替え" aria-label="Permalink to &quot;冗長バックアップと読み取り元切り替え&quot;">​</a></h1><p>冗長バックアップは、すでにアップロード済みのファイルを別の保存先にも複製する機能です。</p><p>通常の閲覧では主ファイルとバックアップファイルの違いは見えません。違うのは、実際にどの保存先から読み込むかだけです。</p><h2 id="できること" tabindex="-1">できること <a class="header-anchor" href="#できること" aria-label="Permalink to &quot;できること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>もう 1 つ保存する</td><td>別チャンネルへ複製し、単一保存先の障害リスクを下げます</td></tr><tr><td>読み取り元を切り替える</td><td>主チャンネルとバックアップチャンネルを切り替えられます</td></tr><tr><td>単一ファイルのバックアップ</td><td>ファイル詳細画面から重要なファイルだけ追加でバックアップできます</td></tr><tr><td>一括バックアップ</td><td>管理画面で複数ファイルを選択して処理できます</td></tr><tr><td>全体バックアップ</td><td>その他設定からフォルダ単位でまとめて補完できます</td></tr></tbody></table><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定 -&gt; 冗長バックアップ</span></span></code></pre></div><p><img src="'+a+'" alt="冗長バックアップ" loading="lazy"></p><p>ここでは特定フォルダ、または全ファイルにまとめてバックアップを追加できます。バックアップ先は手動選択のほか、自動選択も利用できます。</p><h2 id="ファイル詳細からバックアップする" tabindex="-1">ファイル詳細からバックアップする <a class="header-anchor" href="#ファイル詳細からバックアップする" aria-label="Permalink to &quot;ファイル詳細からバックアップする&quot;">​</a></h2><p>管理画面でファイル詳細を開くと、そのファイルだけをバックアップできます。</p><p><img src="'+e+'" alt="ファイル詳細でバックアップ" loading="lazy"></p><p>重要なファイルだけを後から保護したいときに便利です。成功すると、詳細画面に読み取り元の切り替えが表示されます。</p><h2 id="複数ファイルをまとめてバックアップする" tabindex="-1">複数ファイルをまとめてバックアップする <a class="header-anchor" href="#複数ファイルをまとめてバックアップする" aria-label="Permalink to &quot;複数ファイルをまとめてバックアップする&quot;">​</a></h2><p>管理画面でファイルを複数選択し、一括バックアップを実行できます。</p><p><img src="'+d+'" alt="一括バックアップ" loading="lazy"></p><p>入口は違っても、ファイル詳細、複数選択、その他設定の冗長バックアップは同じ仕組みを使います。</p><h2 id="読み取り元の切り替え" tabindex="-1">読み取り元の切り替え <a class="header-anchor" href="#読み取り元の切り替え" aria-label="Permalink to &quot;読み取り元の切り替え&quot;">​</a></h2><table tabindex="0"><thead><tr><th>読み取り元</th><th>説明</th></tr></thead><tbody><tr><td>主チャンネル</td><td>最初にアップロードした保存先から読み込みます</td></tr><tr><td>バックアップチャンネル</td><td>冗長バックアップで作成した保存先から読み込みます</td></tr></tbody></table><p><img src="'+r+'" alt="読み取り元切り替え" loading="lazy"></p><p>切り替え後は、画像表示、動画再生、ダウンロードリンクなどが選択した読み取り元を優先します。</p><h2 id="スキップされるケース" tabindex="-1">スキップされるケース <a class="header-anchor" href="#スキップされるケース" aria-label="Permalink to &quot;スキップされるケース&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ケース</th><th>理由</th></tr></thead><tbody><tr><td>すでにバックアップ済み</td><td>重複保存を避けるため</td></tr><tr><td>主チャンネルと同じ保存先</td><td>同じ場所への複製ではバックアップにならないため</td></tr><tr><td>利用できる保存先がない</td><td>適切な別チャンネルが見つからないため</td></tr></tbody></table><h2 id="削除時の動作" tabindex="-1">削除時の動作 <a class="header-anchor" href="#削除時の動作" aria-label="Permalink to &quot;削除時の動作&quot;">​</a></h2><p>ファイルを削除すると、主ファイルとバックアップファイルの両方が削除されます。</p>',25)])])}const k=o(l,[["render",s]]);export{g as __pageData,k as default};
